#include <string.h>

void val(char* line, char** vals, int* count) {
    char* token = strtok(line, " ");
    *count = 0;
    while (token != NULL) {
        vals[(*count)++] = token;
        token = strtok(NULL, " ");
    }
}

int main() {
    char data[100];
    fgets(data, sizeof(data), stdin);
    data[strcspn(data, "\n")] = '\0';

    char* vals[2];
    int count;
    val(data, vals, &count);

    int n = atoi(vals[0]);
    int m = atoi(vals[1]);

    int result = n + (n - 1) / (m - 1);
    printf("%d\n", result);

    return 0;
}
